def main_menu_keyboard():
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("📅 نصائح أسبوعية", callback_data="weekly_tips"),
         InlineKeyboardButton("🩺 فحص الأعراض", callback_data="symptom_check")],
        [InlineKeyboardButton("🥗 التغذية والنظام الغذائي", callback_data="nutrition"),
         InlineKeyboardButton("🚨 علامات الخطر", callback_data="danger_signs")],
    ])

def week_selection_keyboard():
    buttons, row = [], []
    for week in range(1, 41):
        row.append(InlineKeyboardButton(str(week), callback_data=f"week_{week}"))
        if len(row) == 5:
            buttons.append(row); row = []
    if row: buttons.append(row)
    buttons.append([InlineKeyboardButton("🔙 رجوع", callback_data="main_menu")])
    return InlineKeyboardMarkup(buttons)

def symptom_keyboard():
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("🤢 غثيان", callback_data="sym_غثيان"),
         InlineKeyboardButton("🔙 ألم الظهر", callback_data="sym_ألم ظهر")],
        [InlineKeyboardButton("🦵 تورم القدمين", callback_data="sym_تورم"),
         InlineKeyboardButton("🤕 صداع", callback_data="sym_صداع")],
        [InlineKeyboardButton("🚽 إمساك", callback_data="sym_إمساك")],
        [InlineKeyboardButton("🔙 رجوع", callback_data="main_menu")],
    ])

def back_keyboard():
    return InlineKeyboardMarkup([[InlineKeyboardButton("🔙 القائمة الرئيسية", callback_data="main_menu")]])

async def start(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await update.message.reply_text(
        "🌸 أهلاً بكِ في بوت أمل للعناية بالحوامل 🌸\n\nأنا أمل، مساعدتك الشخصية طوال رحلة حملك الجميلة! 👶\n\nيمكنني مساعدتكِ في:\n📅 نصائح مخصصة لكل أسبوع من الحمل (1-40)\n🩺 فهم الأعراض الشائعة أثناء الحمل\n🥗 إرشادات التغذية الصحية\n🚨 التعرف على علامات الخطر\n\n_تذكّري: أنا لستُ بديلاً عن طبيبكِ، لكنني هنا دائماً لدعمكِ_ 💕\n\nاختاري ما تريدين:",
        parse_mode="Markdown", reply_markup=main_menu_keyboard())

async def help_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await start(update, context)

async def button_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    data = query.data
    if data == "main_menu":
        await query.edit_message_text("🌸 *القائمة الرئيسية*", parse_mode="Markdown", reply_markup=main_menu_keyboard())
    elif data == "weekly_tips":
        await query.edit_message_text("📅 *اختاري الأسبوع (1-40):*", parse_mode="Markdown", reply_markup=week_selection_keyboard())
    elif data.startswith("week_"):
        w = int(data.split("_")[1])
        content = WEEKLY_TIPS.get(w, "المعلومات غير متوفرة.")
        await query.edit_message_text(content, parse_mode="Markdown", reply_markup=back_keyboard())
    elif data == "symptom_check":
        await query.edit_message_text("🩺 *اختاري العَرَض:*", parse_mode="Markdown", reply_markup=symptom_keyboard())
    elif data.startswith("sym_"):
        content = COMMON_SYMPTOMS.get(data[4:], "استشيري طبيبك لهذا العَرَض.")
        await query.edit_message_text(content, parse_mode="Markdown", reply_markup=back_keyboard())
    elif data == "nutrition":
        await query.edit_message_text(NUTRITION_TEXT, parse_mode="Markdown", reply_markup=back_keyboard())
    elif data == "danger_signs":
        await query.edit_message_text(DANGER_SIGNS_TEXT, parse_mode="Markdown", reply_markup=back_keyboard())

async def message_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await update.message.reply_text("يسعدني مساعدتكِ! 💕\nاستخدمي الأزرار:", reply_markup=main_menu_keyboard())

def main():
    if TELEGRAM_TOKEN == "YOUR_TELEGRAM_TOKEN_HERE":
        print("❌ من فضلك ضعي رمز البوت في السطر الأول!")
        return
    asyncio.set_event_loop(asyncio.new_event_loop())
    app = Application.builder().token(TELEGRAM_TOKEN).build()
    app.add_handler(CommandHandler("start", start))
    app.add_handler(CommandHandler("help", help_command))
    app.add_handler(CallbackQueryHandler(button_handler))
    app.add_handler(MessageHandler(filters.TEXT & ~filters.COMMAND, message_handler))
    print("🤰 بوت أمل للحوامل يعمل الآن... 🌸")
    app.run_polling(allowed_updates=Update.ALL_TYPES)

if __name__ == "__main__":
    main()
